#include <stdio.h>
#define MOD 1000000007
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int p, q, r;
        scanf("%d %d %d", &p, &q, &r);
        int A[p], B[q], C[r];
        for (int i = 0; i < p; i++) scanf("%d", &A[i]);
        for (int i = 0; i < q; i++) scanf("%d", &B[i]);
        for (int i = 0; i < r; i++) scanf("%d", &C[i]);
        long long sum = 0;
        for (int i = 0; i < p; i++) {
            for (int j = 0; j < q; j++) {
                for (int k = 0; k < r; k++) {
                    if (A[i] <= B[j] && B[j] >= C[k]) {
                        sum += (long long)(A[i] + B[j]) * (B[j] + C[k]);
                        sum %= MOD;
                    }
                }
            }
        }
        printf("%lld\n", sum);
    }
    return 0;
}

