import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int p = sc.nextInt();
            int q = sc.nextInt();
            int r = sc.nextInt();
            int[] A = new int[p];
            int[] B = new int[q];
            int[] C = new int[r];
            for (int i = 0; i < p; i++) A[i] = sc.nextInt();
            for (int i = 0; i < q; i++) B[i] = sc.nextInt();
            for (int i = 0; i < r; i++) C[i] = sc.nextInt();
            long sum = 0;
            for (int i = 0; i < p; i++) {
                for (int j = 0; j < q; j++) {
                    for (int k = 0; k < r; k++) {
                        if (A[i] <= B[j] && B[j] >= C[k]) {
                            sum += (long)(A[i] + B[j]) * (B[j] + C[k]);
                            sum %= 1000000007;
                        }
                    }
                }
            }
            System.out.println(sum);
